import {DeckGL} from '@deck.gl/react';
import React, {useCallback, useState} from 'react';
import {createRoot} from 'react-dom/client';

import type {MapViewState} from '@deck.gl/core';
import {_GlobeView as GlobeView, MapView} from '@deck.gl/core';
import {TerrainLayer, TerrainLayerProps} from '@deck.gl/geo-layers';

// Set your mapbox token here
const MAPBOX_TOKEN = process.env.MapboxAccessToken; // eslint-disable-line

const INITIAL_VIEW_STATE: MapViewState = {
  latitude: 46.24,
  longitude: -122.18,
  zoom: 11.5,
  bearing: 140,
  pitch: 60,
  maxPitch: 89
};

const TERRAIN_IMAGE = `https://api.mapbox.com/v4/mapbox.terrain-rgb/{z}/{x}/{y}.png?access_token=${MAPBOX_TOKEN}`;
const SURFACE_IMAGE = `https://api.mapbox.com/v4/mapbox.satellite/{z}/{x}/{y}@2x.png?access_token=${MAPBOX_TOKEN}`;

// https://docs.mapbox.com/help/troubleshooting/access-elevation-data/#mapbox-terrain-rgb
// Note - the elevation rendered by this example is greatly exagerated!
const ELEVATION_DECODER: TerrainLayerProps['elevationDecoder'] = {
  rScaler: 6553.6,
  gScaler: 25.6,
  bScaler: 0.1,
  offset: -10000
};

export default function App({
  texture = SURFACE_IMAGE,
  wireframe = false,
  globeView = false,
  zoomOffset = 0,
  minZoom = 0,
  maxZoom = 14,
  visibleMinZoom = 0,
  visibleMaxZoom = 14,
  initialViewState = INITIAL_VIEW_STATE,
  onZoomChange
}: {
  texture?: string;
  wireframe?: boolean;
  globeView?: boolean;
  zoomOffset?: number;
  minZoom?: number;
  maxZoom?: number;
  visibleMinZoom?: number;
  visibleMaxZoom?: number;
  initialViewState?: MapViewState;
  onZoomChange?: (zoom: number) => void;
}) {
  const [viewState, setViewState] = useState(initialViewState);
  const onViewStateChange = useCallback(
    ({viewState: vs}) => {
      setViewState(vs);
      onZoomChange?.(vs.zoom);
    },
    [onZoomChange]
  );

  const layer = new TerrainLayer({
    id: 'terrain',
    minZoom,
    maxZoom,
    visibleMinZoom,
    visibleMaxZoom,
    refinementStrategy: 'best-available',
    elevationDecoder: ELEVATION_DECODER,
    elevationData: TERRAIN_IMAGE,
    texture,
    wireframe,
    zoomOffset,
    color: [255, 255, 255],
    pickable: '3d'
  });

  return (
    <DeckGL
      views={globeView ? new GlobeView() : new MapView()}
      viewState={viewState}
      onViewStateChange={onViewStateChange}
      controller={true}
      parameters={{cull: true}}
      layers={[layer]}
      getTooltip={info => {
        if (info.picked && info.coordinate && info.coordinate.length === 3) {
          const elevation = info.coordinate[2];
          return `Elevation: ${elevation.toFixed(0)} m`;
        }
        return null;
      }}
    />
  );
}

export function renderToDOM(container: HTMLDivElement) {
  createRoot(container).render(<App />);
}
